const items = [];
const now = Date.now();

for (const item of $input.all()) {
  const event = item.json;
  const startTime = event.start?.dateTime || event.start?.date;
  if (!startTime) continue;

  const startMs = new Date(startTime).getTime();
  const minutesUntil = Math.round((startMs - now) / 60000);

  // Nur Events innerhalb 24h melden
  if (minutesUntil < 0 || minutesUntil > 1440) continue;

  let priority = 'low';
  if (minutesUntil <= 30) priority = 'urgent';
  else if (minutesUntil <= 120) priority = 'high';
  else if (minutesUntil <= 480) priority = 'medium';

  const sourceId = `cal-${event.id}-${startTime}`;

  items.push({
    json: {
      source: 'calendar',
      source_id: sourceId,
      summary: `Termin in ${minutesUntil} Min: ${event.summary || 'Unbenannter Termin'}`,
      priority: priority,
      customer_id: $env.CUSTOMER_ID || null,
      buddy_id: $env.BUDDY_ID || null,
      timestamp: startTime,
      details: {
        event_title: event.summary || 'Unbenannter Termin',
        start_time: startTime,
        end_time: event.end?.dateTime || event.end?.date,
        location: event.location || null,
        minutes_until: minutesUntil,
        calendar_name: event.organizer?.displayName || 'Kalender'
      }
    }
  });
}
return items;
